import math

def is_prime(n: int) -> bool:
    """Checks if a number n is prime."""
    if n <= 1:
        return False
    if n <= 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True

def solve(nums: list[int]) -> int:
    """
    Calculates the minimum operations needed to make nums an alternating prime array.
    """
    total_operations = 0

    for i in range(len(nums)):
        n = nums[i]

        if i % 2 == 0:
            # Even index: Target must be Prime
            # Find smallest n_prime >= n such that is_prime(n_prime) is True
            n_prime = n
            while not is_prime(n_prime):
                n_prime += 1

            operations = n_prime - n
            total_operations += operations
        else:
            # Odd index: Target must be Non-Prime
            # Find smallest n_non_prime >= n such that is_prime(n_non_prime) is False
            n_non_prime = n
            while is_prime(n_non_prime):
                n_non_prime += 1

            operations = n_non_prime - n
            total_operations += operations

    return total_operations
